1300	fn rbtdrf_rv_rbrv_all_vessels(dir: &Path) -> rbtdre_Verdict {
1301	    let root = match std::env::current_dir() {
1302	        Ok(r) => r,
1303	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1304	    };
1305	
1306	    // Discover vessels: source rbrr.env to get RBRR_VESSEL_DIR, scan it
1307	    let buv = root.join("Tools/buk/buv_validation.sh");
1308	    let rbk = root.join("Tools/rbk");
1309	    let buv_p = rbtdrx_native_to_posix(&buv);
1310	    let rbk_p = rbtdrx_native_to_posix(&rbk);
1311	    let script = format!(
1312	        "set -euo pipefail\n\
1313	         source '{}'\n\
1314	         source '{}/rbcc_Constants.sh'\n\
1315	         source '{}/rbgc_Constants.sh'\n\
1316	         source '{}/rbrr_regime.sh'\n\
1317	         source '{}/rbrd_regime.sh'\n\
1318	         source '{}/rbdc_DerivedConstants.sh'\n\
1319	         zbuv_kindle\nzrbcc_kindle\n\
1320	         source \"${{PWD}}/{moorings}/rbrr.env\"\n\
1321	         source \"${{PWD}}/{moorings}/rbrd.env\"\n\
1322	         zrbrr_kindle\nzrbrd_kindle\nzrbrr_enforce\nzrbrd_enforce\nzrbdc_kindle\n\
1323	         echo \"${{RBRR_VESSEL_DIR}}\"",
1324	        buv_p,
1325	        rbk_p, rbk_p, rbk_p, rbk_p, rbk_p,
1326	        moorings = crate::rbtdgc_consts::RBTDGC_MOORINGS_DIR,
1327	    );
1328	
1329	    let vessel_dir = match rbtdrf_run_bash(&root, &script, dir, "rbrv-discover") {
1330	        Ok((0, stdout, _)) => stdout.trim().to_string(),
1331	        Ok((code, _, _)) => {
1332	            return rbtdre_Verdict::Fail(format!("vessel discovery failed (exit {})", code));
1333	        }
1334	        Err(e) => return rbtdre_Verdict::Fail(e),
1335	    };
1336	
1337	    let entries = match std::fs::read_dir(&vessel_dir) {
1338	        Ok(e) => e,
1339	        Err(e) => {
1340	            return rbtdre_Verdict::Fail(format!("cannot read {}: {}", vessel_dir, e));
1341	        }
1342	    };
1343	
1344	    let mut found = false;
1345	    for entry in entries.filter_map(|e| e.ok()) {
1346	        let path = entry.path();
1347	        if path.is_dir() && path.join("rbrv.env").exists() {
1348	            found = true;
1349	            let sigil = entry.file_name().to_string_lossy().to_string();
1350	            if let Err(e) = rbtdrf_run_tt(
1351	                &root, RBTDGC_VALIDATE_VESSEL, &[&sigil], dir,
1352	                &format!("rbrv-{}-validate", sigil),
1353	            ) {
1354	                return rbtdre_Verdict::Fail(e);
1355	            }
1356	        }
1357	    }
1358	
1359	    if !found {
1360	        return rbtdre_Verdict::Fail(format!("no vessels found in {}", vessel_dir));
1361	    }
1362	    rbtdre_Verdict::Pass
1363	}
