1365	fn rbtdrf_rv_rbrn_all_nameplates(dir: &Path) -> rbtdre_Verdict {
1366	    let root = match std::env::current_dir() {
1367	        Ok(r) => r,
1368	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1369	    };
1370	
1371	    // Discover nameplates by listing rbmm_moorings/*/rbrn.env
1372	    let rbk_dir = root.join(crate::rbtdgc_consts::RBTDGC_MOORINGS_DIR);
1373	    let entries = match std::fs::read_dir(&rbk_dir) {
1374	        Ok(e) => e,
1375	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot read {}: {}", crate::rbtdgc_consts::RBTDGC_MOORINGS_DIR, e)),
1376	    };
1377	
1378	    let mut found = false;
1379	    for entry in entries.filter_map(|e| e.ok()) {
1380	        let path = entry.path();
1381	        if path.is_dir() && path.join("rbrn.env").exists() {
1382	            found = true;
1383	            let moniker = entry.file_name().to_string_lossy().to_string();
1384	            if let Err(e) = rbtdrf_run_tt(
1385	                &root, RBTDGC_VALIDATE_NAMEPLATE, &[&moniker], dir,
1386	                &format!("rbrn-{}-validate", moniker),
1387	            ) {
1388	                return rbtdre_Verdict::Fail(e);
1389	            }
1390	        }
1391	    }
1392	
1393	    if !found {
1394	        return rbtdre_Verdict::Fail(format!("no nameplates found in {}/", crate::rbtdgc_consts::RBTDGC_MOORINGS_DIR));
