1644	
1645	/// rbw-dU empty-arg refusal — BBAA9 contract. Invoking rbw-dU with no
1646	/// argument must die non-zero and emit the rbw-dl pointer (operator
1647	/// discovery for candidate depot project IDs). BUW dispatch merges
1648	/// stderr→stdout via `2>&1` (bud_dispatch.sh:372), so the captured
1649	/// stdout carries the buc_warn/buc_info/buc_tabtarget/buc_die output
1650	/// from rbgp_depot_unmake's no-arg branch (rbgp_Payor.sh:937-942).
1651	///
1652	/// Pure shell, no GCP traffic — refusal lands before authenticate.
1653	fn rbtdrf_rs_unmake_empty_arg_refusal(dir: &Path) -> rbtdre_Verdict {
1654	    let root = match std::env::current_dir() {
1655	        Ok(r) => r,
1656	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1657	    };
1658	
1659	    let tt = match rbtdri_find_tabtarget_global(&root, RBTDGC_UNMAKE_DEPOT) {
1660	        Ok(p) => p,
1661	        Err(e) => return rbtdre_Verdict::Fail(e),
1662	    };
1663	
1664	    let output = match rbtdri_tabtarget_command(&tt).current_dir(&root).output() {
1665	        Ok(o) => o,
1666	        Err(e) => {
1667	            return rbtdre_Verdict::Fail(format!(
1668	                "failed to run {}: {}",
1669	                tt.display(),
1670	                e
1671	            ));
1672	        }
1673	    };
1674	
1675	    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
1676	    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
1677	    let code = output.status.code().unwrap_or(-1);
1678	    let _ = std::fs::write(dir.join("empty-arg-stdout.txt"), &stdout);
1679	    let _ = std::fs::write(dir.join("empty-arg-stderr.txt"), &stderr);
1680	
1681	    if code == 0 {
1682	        return rbtdre_Verdict::Fail(format!(
1683	            "{} exited 0 with no argument — BBAA9 empty-arg refusal contract violated",
1684	            RBTDGC_UNMAKE_DEPOT
1685	        ));
1686	    }
1687	
1688	    let combined = format!("{}{}", stdout, stderr);
1689	    if !combined.contains(RBTDGC_LIST_DEPOT) {
1690	        return rbtdre_Verdict::Fail(format!(
1691	            "{} empty-arg refusal did not point at {} for operator discovery\n\
1692	             stdout:\n{}\n\nstderr:\n{}",
1693	            RBTDGC_UNMAKE_DEPOT, RBTDGC_LIST_DEPOT, stdout, stderr
1694	        ));
1695	    }
1696	
1697	    rbtdre_Verdict::Pass
1698	}
