1775	fn rbtdrf_dh_all_vessels_pass(dir: &Path) -> rbtdre_Verdict {
1776	    let root = match std::env::current_dir() {
1777	        Ok(r) => r,
1778	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1779	    };
1780	
1781	    // Resolve RBRR_VESSEL_DIR via one-shot bash (kindle ceremony unavoidable
1782	    // for derived-path resolution).
1783	    let buv = root.join("Tools/buk/buv_validation.sh");
1784	    let rbk = root.join("Tools/rbk");
1785	    let buv_p = rbtdrx_native_to_posix(&buv);
1786	    let rbk_p = rbtdrx_native_to_posix(&rbk);
1787	    let resolve_script = format!(
1788	        "set -euo pipefail\n\
1789	         source '{}'\n\
1790	         source '{}/rbcc_Constants.sh'\n\
1791	         source '{}/rbgc_Constants.sh'\n\
1792	         source '{}/rbrr_regime.sh'\n\
1793	         source '{}/rbrd_regime.sh'\n\
1794	         source '{}/rbdc_DerivedConstants.sh'\n\
1795	         zbuv_kindle\nzrbcc_kindle\n\
1796	         source \"${{PWD}}/{moorings}/rbrr.env\"\n\
1797	         source \"${{PWD}}/{moorings}/rbrd.env\"\n\
1798	         zrbrr_kindle\nzrbrd_kindle\nzrbrr_enforce\nzrbrd_enforce\nzrbdc_kindle\n\
1799	         printf '%s' \"${{RBRR_VESSEL_DIR}}\"",
1800	        buv_p,
1801	        rbk_p, rbk_p, rbk_p, rbk_p, rbk_p,
1802	        moorings = crate::rbtdgc_consts::RBTDGC_MOORINGS_DIR,
1803	    );
1804	    let vessel_dir = match rbtdrf_run_bash(&root, &resolve_script, dir, "resolve-vessel-dir") {
1805	        Ok((0, stdout, _)) => stdout,
1806	        Ok((code, _, stderr)) => {
1807	            return rbtdre_Verdict::Fail(format!(
1808	                "resolve RBRR_VESSEL_DIR failed (exit {}): {}",
1809	                code, stderr
1810	            ));
1811	        }
1812	        Err(e) => return rbtdre_Verdict::Fail(e),
1813	    };
1814	    let vessel_dir = vessel_dir.trim();
1815	    if vessel_dir.is_empty() {
1816	        return rbtdre_Verdict::Fail("RBRR_VESSEL_DIR resolved to empty string".to_string());
1817	    }
1818	
1819	    let entries = match std::fs::read_dir(vessel_dir) {
1820	        Ok(e) => e,
1821	        Err(e) => {
1822	            return rbtdre_Verdict::Fail(format!(
1823	                "read_dir({}) failed: {}",
1824	                vessel_dir, e
1825	            ));
1826	        }
1827	    };
1828	
1829	    // rbw-fhv silently succeeds on non-conjure vessels (hygiene contract is
1830	    // vacuously satisfied where there's no local Dockerfile), so theurge
1831	    // iterates without pre-filtering — surface integrity stays intact and
1832	    // no rbrv.env internals are touched here.
1833	    let mut count: usize = 0;
1834	    for entry in entries {
1835	        let entry = match entry {
1836	            Ok(e) => e,
1837	            Err(e) => return rbtdre_Verdict::Fail(format!("dir entry error: {}", e)),
1838	        };
1839	        let path = entry.path();
1840	        if !path.is_dir() {
1841	            continue;
1842	        }
1843	        if !path.join("rbrv.env").is_file() {
1844	            continue;
1845	        }
1846	        let sigil = match path.file_name().and_then(|s| s.to_str()) {
1847	            Some(s) => s.to_string(),
1848	            None => continue,
1849	        };
1850	
1851	        if let Err(e) = rbtdrf_run_tt(
1852	            &root,
1853	            RBTDGC_HYGIENE_CHECK_VESSEL,
1854	            &[&sigil],
1855	            dir,
1856	            &format!("vessel-{}", sigil),
1857	        ) {
