1873	// ── Foundry-path cases ──────────────────────────────────────
1874	//
1875	// Drives zrbfc_native_path_capture directly: source rbfcb_BuildHost.sh, force
1876	// BURD_OSTYPE, assert the normalized stdout (or, for the bare-absolute
1877	// unsurveyed shape, that the capture returns non-zero). The normalizer is
1878	// sentinel-free and reads only its argument plus BURD_OSTYPE, so this stays a
1879	// dependency-free unit test — no foundry kindle, no regime, no credentials —
1880	// and exercises the Cygwin transform on any host by forcing the platform fact.
1881	
1882	fn rbtdrf_np_run(
1883	    dir: &Path,
1884	    label: &str,
1885	    ostype: &str,
1886	    input: &str,
1887	    expect: Option<&str>,
1888	) -> rbtdre_Verdict {
1889	    let root = match std::env::current_dir() {
1890	        Ok(r) => r,
1891	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1892	    };
1893	    let rbfcb = root.join("Tools/rbk/rbfcb_BuildHost.sh");
1894	
1895	    let assertion = match expect {
1896	        Some(out) => format!("test \"$(zrbfc_native_path_capture '{}')\" = '{}'", input, out),
1897	        None => format!("zrbfc_native_path_capture '{}'", input),
1898	    };
1899	    let script = format!(
1900	        "set -euo pipefail\nsource '{}'\nexport BURD_OSTYPE='{}'\n{}",
1901	        rbtdrx_native_to_posix(&rbfcb),
1902	        ostype,
1903	        assertion,
1904	    );
1905	
1906	    let expect_ok = expect.is_some();
1907	    match rbtdrf_run_bash(&root, &script, dir, label) {
1908	        Ok((code, _, _)) => {
1909	            let ok = code == 0;
1910	            if ok == expect_ok {
1911	                rbtdre_Verdict::Pass
1912	            } else if expect_ok {
1913	                rbtdre_Verdict::Fail(format!("{}: expected ok, got exit {}", label, code))
1914	            } else {
1915	                rbtdre_Verdict::Fail(format!("{}: expected non-zero (unsurveyed), got exit 0", label))
1916	            }
1917	        }
1918	        Err(e) => rbtdre_Verdict::Fail(format!("{}: {}", label, e)),
1919	    }
1920	}
