1948	//
1949	// Drives zrbld_spine_validate — the Lode capture-assembly spine's dispatch-time
1950	// substitution-coverage check — directly: write a substitution-keys file and an
1951	// already-include-expanded step body, source buv_validation + rblds_Spine and
1952	// kindle buv so buc_log_args resolves, then assert the check accepts a fully
1953	// covered body and returns non-zero at the first _RBGL_* reference absent from
1954	// the keys. The check is sentinel-free and reads only its two file arguments, so
1955	// this stays a dependency-free unit test — no rbld kindle, no regime, no creds.
1956	
1957	fn rbtdrf_rc_run(
1958	    dir: &Path,
1959	    label: &str,
1960	    keys: &str,
1961	    body: &str,
1962	    expect_ok: bool,
1963	) -> rbtdre_Verdict {
1964	    let root = match std::env::current_dir() {
1965	        Ok(r) => r,
1966	        Err(e) => return rbtdre_Verdict::Fail(format!("cannot get cwd: {}", e)),
1967	    };
1968	    let keys_file = dir.join(format!("{}-keys.txt", label));
1969	    let body_file = dir.join(format!("{}-body.sh", label));
1970	    if let Err(e) = std::fs::write(&keys_file, keys) {
1971	        return rbtdre_Verdict::Fail(format!("{}: write keys failed: {}", label, e));
1972	    }
1973	    if let Err(e) = std::fs::write(&body_file, body) {
1974	        return rbtdre_Verdict::Fail(format!("{}: write body failed: {}", label, e));
1975	    }
1976	    let buv = root.join("Tools/buk/buv_validation.sh");
1977	    let spine = root.join("Tools/rbk/rblds_Spine.sh");
1978	    let script = format!(
1979	        "set -euo pipefail\n\
1980	         source '{}'\n\
1981	         source '{}'\n\
1982	         zbuv_kindle\n\
1983	         zrbld_spine_validate '{}' '{}'",
1984	        rbtdrx_native_to_posix(&buv),
1985	        rbtdrx_native_to_posix(&spine),
1986	        rbtdrx_native_to_posix(&keys_file),
1987	        rbtdrx_native_to_posix(&body_file),
1988	    );
1989	
1990	    let expect = if expect_ok { "ok" } else { "non-zero (uncovered)" };
1991	    match rbtdrf_run_bash(&root, &script, dir, label) {
1992	        Ok((code, _, _)) => {
1993	            if (code == 0) == expect_ok {
1994	                rbtdre_Verdict::Pass
1995	            } else {
1996	                rbtdre_Verdict::Fail(format!("{}: expected {}, got exit {}", label, expect, code))
1997	            }
1998	        }
1999	        Err(e) => rbtdre_Verdict::Fail(format!("{}: {}", label, e)),
2000	    }
2001	}
